package com.parkflow.mall.gateway.payment;
import org.springframework.beans.factory.annotation.Value; import org.springframework.http.*; import org.springframework.stereotype.Service; import org.springframework.web.client.*;
@Service public class PaymentServiceProxy { private final RestTemplate rest; private final String base; public PaymentServiceProxy(RestTemplate r,@Value("${gateway.payment-base-url}") String b){rest=r;base=b;} public ResponseEntity<String> forward(String path,HttpMethod method,String body,String auth,String key){HttpHeaders h=new HttpHeaders();h.setContentType(MediaType.APPLICATION_JSON);if(auth!=null)h.set(HttpHeaders.AUTHORIZATION,auth);if(key!=null)h.set("Idempotency-Key",key);try{var r=rest.exchange(base+path,method,new HttpEntity<>(body,h),String.class);return ResponseEntity.status(r.getStatusCode()).contentType(MediaType.APPLICATION_JSON).body(r.getBody());}catch(HttpStatusCodeException e){return ResponseEntity.status(e.getStatusCode()).contentType(MediaType.APPLICATION_JSON).body(e.getResponseBodyAsString());}catch(ResourceAccessException e){return ResponseEntity.status(HttpStatus.BAD_GATEWAY).body("{\"error\":\"payment-service unavailable\"}");}} }
